// 6 Hubs × 6 Queries = 36 Items für textSearch-Loop
// Spec §3.1 + §3.2
const hubs = [
  { name: 'Hamburg',    lat: 53.5528, lng: 10.0067 },
  { name: 'Lübeck',     lat: 53.8654, lng: 10.6866 },
  { name: 'Kiel',       lat: 54.3233, lng: 10.1228 },
  { name: 'Flensburg',  lat: 54.7836, lng: 9.4321  },
  { name: 'Neumünster', lat: 54.0732, lng: 9.9819  },
  { name: 'Husum',      lat: 54.4750, lng: 9.0500  }
];
const queryTemplates = [
  'KFZ Werkstatt',
  'Autowerkstatt',
  'Reifenhandel',
  'Karosseriebau',
  'Autoglas',
  'Auto Lackiererei'
];
const RADIUS_M = 30000;
const items = [];
for (const hub of hubs) {
  for (const qt of queryTemplates) {
    items.push({
      json: {
        hub_name: hub.name,
        hub_lat: hub.lat,
        hub_lng: hub.lng,
        radius_m: RADIUS_M,
        base_query: qt,
        query: qt + ' ' + hub.name
      }
    });
  }
}
return items;

// Korreliert API-Responses mit Hub-Context per Index — sicher solange
// HTTP Request einmalig pro Input-Item ausgeführt hat (n8n-Default).
const responses = $input.all();
const matrix = $('Build Hub Query Matrix').all();
const flat = [];
for (let i = 0; i < responses.length; i++) {
  const resp = responses[i].json || {};
  const hubCtx = matrix[i] ? matrix[i].json : {};
  if (resp.error_message) {
    // Quota- oder Auth-Fehler — nicht silent durchwinken
    throw new Error('Places textSearch error for hub=' + hubCtx.hub_name + ' query=' + hubCtx.query + ': ' + resp.error_message);
  }
  if (resp.status && resp.status !== 'OK' && resp.status !== 'ZERO_RESULTS') {
    // OVER_QUERY_LIMIT, REQUEST_DENIED, INVALID_REQUEST — Workflow stoppen (Spec §5.2)
    if (resp.status === 'OVER_QUERY_LIMIT') {
      throw new Error('Google Places quota exhausted (OVER_QUERY_LIMIT). Workflow halted per Spec §5.2.');
    }
    throw new Error('Places textSearch unexpected status=' + resp.status + ' for query=' + hubCtx.query);
  }
  for (const place of (resp.results || [])) {
    flat.push({
      json: {
        place_id: place.place_id,
        name: place.name,
        formatted_address: place.formatted_address || '',
        rating: place.rating || null,
        user_ratings_total: place.user_ratings_total || 0,
        business_status: place.business_status || null,
        geometry: place.geometry || null,
        _hub_name: hubCtx.hub_name,
        _hub_lat: hubCtx.hub_lat,
        _hub_lng: hubCtx.hub_lng,
        _query: hubCtx.query,
        _base_query: hubCtx.base_query
      }
    });
  }
}
return flat;

// Spec §3.4. Reihenfolge der Checks ist optimiert für Cheapest-First.
const CHAIN_BLOCKLIST = [
  'atu', 'a.t.u', 'a t u',
  'pit-stop', 'pitstop', 'pit stop',
  'vergölst', 'vergoelst',
  'euromaster',
  'bosch service', 'bosch car service',
  '1a autoservice', '1a-autoservice',
  'autocrew',
  'premio'
];
const NON_SH_MARKERS = [
  'niedersachsen', 'mecklenburg-vorpommern', 'mecklenburg vorpommern',
  'bremen ', 'brandenburg', 'sachsen-anhalt', 'sachsen anhalt'
];
function haversineKm(lat1, lng1, lat2, lng2) {
  const R = 6371;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);
  const a = Math.sin(dLat/2)**2 + Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) * Math.sin(dLng/2)**2;
  return 2 * R * Math.asin(Math.sqrt(a));
}
const kept = [];
for (const item of $input.all()) {
  const p = item.json;
  // 1. business_status
  if (p.business_status && p.business_status !== 'OPERATIONAL') continue;
  // 2. Filialketten
  const nameLow = (p.name || '').toLowerCase();
  if (CHAIN_BLOCKLIST.some(c => nameLow.includes(c))) continue;
  // 3. Bundesland-Marker im address (Pre-Filter; finale Adresse kommt aus Details)
  const addrLow = (p.formatted_address || '').toLowerCase();
  if (NON_SH_MARKERS.some(m => addrLow.includes(m))) continue;
  // 4. Distanz zum Hub
  if (p.geometry && p.geometry.location) {
    const d = haversineKm(p._hub_lat, p._hub_lng, p.geometry.location.lat, p.geometry.location.lng);
    if (d > 30) continue;
    p._dist_to_hub_km = Math.round(d * 10) / 10;
  }
  // (Website-Check erfolgt erst nach Places details, weil textSearch website nicht liefert)
  kept.push({ json: p });
}
// Lokales Dedup (gleiche place_id durch verschiedene Hub-Queries) — höchstes user_ratings_total gewinnt
const byId = new Map();
for (const it of kept) {
  const pid = it.json.place_id;
  if (!pid) continue;
  const existing = byId.get(pid);
  if (!existing || (it.json.user_ratings_total || 0) > (existing.json.user_ratings_total || 0)) {
    byId.set(pid, it);
  }
}
return Array.from(byId.values());

// Existing place_ids aus Sheet (lead_id-Format: kfz-hh-{place_id_hash8}).
// Spec §5.1 Node 7 erweitert: schon gescorte Leads NICHT erneut bewerten.
// FNV-1a 32-bit (n8n Code-Sandbox erlaubt kein require('crypto');
// Repo-Style aus scripts/lib/variant.mjs).
function fnv1aHex8(s) {
  let h = 0x811c9dc5;
  const str = String(s);
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}
function leadIdFor(placeId) {
  return 'kfz-hh-' + fnv1aHex8(placeId);
}
const sheetRows = $input.all();
const existingLeadIds = new Set();
for (const row of sheetRows) {
  if (row.json && row.json.lead_id) {
    existingLeadIds.add(String(row.json.lead_id).trim());
  }
}
const candidates = $('Pre-Filter (Bundesland · Chains · Distanz · Status)').all();
const newLeads = [];
for (const c of candidates) {
  const pid = c.json.place_id;
  if (!pid) continue;
  const lid = leadIdFor(pid);
  if (existingLeadIds.has(lid)) continue;
  newLeads.push({
    json: {
      ...c.json,
      lead_id: lid
    }
  });
}
return newLeads;

// Decode Website Binary — Phase-2 Bug-Fix (2026-05-03).
// Begründung: HTTP Website Fetch läuft mit responseFormat: 'file'. Auf der n8n-VPS
// ist N8N_DEFAULT_BINARY_DATA_MODE=filesystem-v2; dadurch ist $binary.data.data
// NICHT base64-content sondern der Literal-String 'filesystem-v2'. Das vorherige
// `Buffer.from($binary.data.data, 'base64')` lieferte deshalb 9 Bytes Garbage
// (~)^³+-zo¯ in execution 66 verifiziert via n8n-API).
//
// Lösung: hier — direkt nach HTTP Website Fetch — wird das Binary via
// `this.helpers.getBinaryDataBuffer($itemIndex, propertyName)` real von Disk
// gelesen, charset-aware decodiert und als String in $json._website_html_decoded
// abgelegt. Das HTML Truncate-Node downstream operiert dann auf String, nicht
// mehr auf Binary für die Website. (Impressum-Binary bleibt direct-input dort
// und wird mit dem gleichen Helper gelesen.)

function decodeBufferSmart(buf, contentTypeHeader) {
  if (!buf || buf.length === 0) return { text: '', charset: '' };
  const ct = String(contentTypeHeader || '').toLowerCase();
  const cm = ct.match(/charset=([^;\s]+)/);
  const declared = cm ? cm[1].toLowerCase() : '';
  if (declared === 'iso-8859-1' || declared === 'latin-1' || declared === 'windows-1252') {
    return { text: new TextDecoder('iso-8859-1').decode(buf), charset: 'iso-8859-1' };
  }
  if (declared === 'utf-8' || declared === 'utf8') {
    return { text: new TextDecoder('utf-8', { fatal: false }).decode(buf), charset: 'utf-8' };
  }
  // Kein Charset-Header — Heuristik: UTF-8 versuchen, bei >5 Replacement-Chars
  // oder >5% Verhältnis auf iso-8859-1 umschalten (alte Apache/PHP-Cases).
  const utf8 = new TextDecoder('utf-8', { fatal: false }).decode(buf);
  if (utf8.length === 0) return { text: utf8, charset: 'utf-8' };
  const replCount = (utf8.match(/\uFFFD/g) || []).length;
  if (replCount > 5 || replCount / utf8.length > 0.05) {
    return { text: new TextDecoder('iso-8859-1').decode(buf), charset: 'iso-8859-1-fallback' };
  }
  return { text: utf8, charset: 'utf-8' };
}

async function readBufferTolerant(helpers, itemIndex, bin) {
  if (!bin) return null;
  // Memory-Mode: data ist base64-string mit echtem Inhalt (nicht 'filesystem-v2'-Marker).
  if (typeof bin.data === 'string' && bin.data && bin.data !== 'filesystem-v2' && bin.data.length > 32) {
    try {
      const buf = Buffer.from(bin.data, 'base64');
      if (buf.length > 0) return buf;
    } catch (e) { /* fall through */ }
  }
  // Filesystem-v2-Mode: helper benutzen.
  if (helpers && typeof helpers.getBinaryDataBuffer === 'function') {
    try {
      const buf = await helpers.getBinaryDataBuffer(itemIndex, 'data');
      if (buf && buf.length > 0) return buf;
    } catch (e) { /* fall through */ }
  }
  return null;
}

const headers = ($json && $json.headers) || {};
const statusCode = $json && $json.statusCode != null ? $json.statusCode : null;
const ct = headers['content-type'] || headers['Content-Type'] || '';
const bin = ($binary && $binary.data) || null;

const buf = await readBufferTolerant(this.helpers, $itemIndex, bin);
const decoded = buf ? decodeBufferSmart(buf, ct) : { text: '', charset: '' };

return {
  json: Object.assign({}, $json, {
    _website_html_decoded: decoded.text,
    _website_charset_used: decoded.charset,
    _website_buffer_bytes: bin && bin.bytes != null ? bin.bytes : (buf ? buf.length : 0),
    _website_status_code: statusCode
  })
};

// HTML Truncate + Merge Context — Phase-2 (4 Datenqualitäts-Patches).
// Patches:
//   P1: Inhaber-Pattern-V2 — HTML-Tag-Normalisierung + erweiterte TMG-Labels
//   P2: Domain-Filter-Strict — keine Fremd-Domain als Fallback, mismatch-Flag
//   P3: Charset-Phase-2 — Buffer + TextDecoder mit iso-8859-1-Fallback
//   P4: No-SSL-Signal — Original-URL-Scheme erhalten, _no_ssl als statisches Field
//
// Bug-Fix 2026-05-03 (P3-Pfad):
// - Website-HTML kommt jetzt vor-decodiert aus dem neuen Node 'Decode Website Binary'
//   als $('Decode Website Binary').all()[i].json._website_html_decoded.
// - Impressum-Binary ist direct-input dieses Nodes und wird via
//   `await this.helpers.getBinaryDataBuffer(i, 'data')` von Disk gelesen,
//   weil n8n-VPS auf filesystem-v2-Mode läuft (binary.data.data === 'filesystem-v2').

const websiteDecoded = $('Decode Website Binary').all();
const websiteOrig = $('HTTP Website Fetch').all();
const impressumItems = $('HTTP Impressum Fetch').all();
const detailItems = $('HTTP Places details').all();
const dedupItems = $('Dedup vs Sheet').all();
const helpers = this.helpers || null;

// === Patch 3: Smart Decode ===
// Trigger Latin-1-Fallback: explizit-Latin-1-Header ODER >5 Mojibake-Chars
// (Phase-1-Log: Verbund-Sites ~92 in 50kB) ODER >5% Verhältnis (Auftrag-Spec).
function decodeBufferSmart(buf, contentTypeHeader) {
  if (!buf) return '';
  const ct = String(contentTypeHeader || '').toLowerCase();
  const cm = ct.match(/charset=([^;\s]+)/);
  const declared = cm ? cm[1].toLowerCase() : '';
  if (declared === 'iso-8859-1' || declared === 'latin-1' || declared === 'windows-1252') {
    return new TextDecoder('iso-8859-1').decode(buf);
  }
  if (declared === 'utf-8' || declared === 'utf8') {
    return new TextDecoder('utf-8', { fatal: false }).decode(buf);
  }
  const utf8 = new TextDecoder('utf-8', { fatal: false }).decode(buf);
  if (utf8.length === 0) return utf8;
  const replCount = (utf8.match(/\uFFFD/g) || []).length;
  if (replCount > 5 || replCount / utf8.length > 0.05) {
    return new TextDecoder('iso-8859-1').decode(buf);
  }
  return utf8;
}

// Liest Buffer tolerant: zuerst Memory-Mode (echtes base64 in bin.data), sonst
// helper für filesystem-v2-Mode. Funktioniert nur für direct-input items —
// für upstream HTTP-Nodes ist binary nicht über den Helper erreichbar.
async function readBufferTolerant(itemIndex, bin) {
  if (!bin) return null;
  if (typeof bin.data === 'string' && bin.data && bin.data !== 'filesystem-v2' && bin.data.length > 32) {
    try {
      const buf = Buffer.from(bin.data, 'base64');
      if (buf.length > 0) return buf;
    } catch (e) { /* fall through */ }
  }
  if (helpers && typeof helpers.getBinaryDataBuffer === 'function') {
    try {
      const buf = await helpers.getBinaryDataBuffer(itemIndex, 'data');
      if (buf && buf.length > 0) return buf;
    } catch (e) { /* fall through */ }
  }
  return null;
}

// Website: HTML kommt vor-decodiert aus dem Decode-Node; Status/Headers
// aus dem Original-HTTP-Node (für Reachability-Check).
function readWebsite(i) {
  const decItem = websiteDecoded[i];
  const origItem = websiteOrig[i];
  const html = decItem && decItem.json ? (decItem.json._website_html_decoded || '') : '';
  const oj = (origItem && origItem.json) || {};
  const statusCode = oj.statusCode != null ? oj.statusCode : (decItem && decItem.json && decItem.json._website_status_code != null ? decItem.json._website_status_code : null);
  return { html: html, statusCode: statusCode, headers: oj.headers || {} };
}

// Impressum: direct input — helper-Pfad funktioniert.
async function readImpressum(i) {
  const item = impressumItems[i];
  if (!item) return { html: '', statusCode: null, headers: {} };
  const j = item.json || {};
  const headers = j.headers || {};
  const statusCode = j.statusCode != null ? j.statusCode : null;
  const bin = (item.binary && item.binary.data) || null;
  const buf = await readBufferTolerant(i, bin);
  if (buf) {
    const html = decodeBufferSmart(buf, headers['content-type'] || headers['Content-Type'] || '');
    return { html: html, statusCode: statusCode, headers: headers };
  }
  // Legacy-Fallback: text-mode response
  if (typeof j.data === 'string' && j.data.length > 0) {
    return { html: j.data, statusCode: statusCode, headers: headers };
  }
  return { html: '', statusCode: statusCode, headers: headers };
}

function isReachable(parsed) {
  return parsed && parsed.statusCode === 200 && typeof parsed.html === 'string' && parsed.html.length > 0;
}

function htmlText(s) {
  if (!s) return '';
  return String(s)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/(p|div|li|h[1-6]|tr)>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/[ \t]+/g, ' ');
}

function stripScriptStyleOnly(s) {
  if (!s) return '';
  return String(s)
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ');
}

function truncateChars(s, n) {
  if (!s) return '';
  return s.length > n ? s.slice(0, n) : s;
}

// === Patch 2: Email + Domain-Strict ===
const EMAIL_BLOCKLIST_PREFIXES = ['webmaster@', 'postmaster@', 'no-reply@', 'noreply@', 'admin@', 'hostmaster@', 'abuse@', 'spam@'];
const EMAIL_KANZLEI_HINTS = ['kanzlei', 'rechtsanwalt', 'datenschutz-anwalt', 'datenschutz-beauftragter', 'dsb-'];

function extractEmails(html) {
  const found = new Set();
  if (!html) return found;
  const mailtoRe = /href=["']mailto:([^"'?<>\s]+)/gi;
  let m;
  while ((m = mailtoRe.exec(html)) !== null) {
    let e = m[1].trim();
    try { e = decodeURIComponent(e); } catch (err) { /* malformed */ }
    e = e.toLowerCase();
    if (e.includes('@') && !e.includes('�')) found.add(e);
  }
  const plainRe = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}\b/g;
  let p;
  while ((p = plainRe.exec(html)) !== null) {
    const e = p[0].toLowerCase();
    if (!e.includes('�')) found.add(e);
  }
  return found;
}

function pickBestEmail(emails, websiteUrl) {
  let candidates = Array.from(emails);
  candidates = candidates.filter(e => !EMAIL_BLOCKLIST_PREFIXES.some(b => e.startsWith(b)));
  if (!candidates.length) return { email: '', mismatch: false };
  let ownHost = '';
  try {
    if (websiteUrl) ownHost = new URL(websiteUrl).hostname.replace(/^www\./, '').toLowerCase();
  } catch (e) { /* */ }
  const ownRoot = ownHost ? ownHost.split('.').slice(-2).join('.') : '';
  const ownDomain = candidates.filter(e => {
    const ed = (e.split('@')[1] || '').toLowerCase();
    return ownRoot && ed.endsWith(ownRoot);
  });
  // Patch 2: kein Fallback auf Fremd-Domain — leer + mismatch-Flag
  if (!ownDomain.length) {
    return { email: '', mismatch: true };
  }
  function emailScore(e) {
    if (e.startsWith('info@')) return 100;
    if (e.startsWith('kontakt@')) return 90;
    if (e.startsWith('service@')) return 80;
    if (e.startsWith('werkstatt@')) return 75;
    if (e.startsWith('office@')) return 70;
    if (EMAIL_KANZLEI_HINTS.some(k => e.includes(k))) return 5;
    return 50;
  }
  ownDomain.sort((a, b) => emailScore(b) - emailScore(a));
  return { email: ownDomain[0] || '', mismatch: false };
}

// === Patch 1: Inhaber-V2 ===
const NAME_WORD = '[A-ZÄÖÜ][a-zäöüß]+(?:-[A-ZÄÖÜ][a-zäöüß]+)*';
const NAME_RE = new RegExp('^(' + NAME_WORD + '\\s+' + NAME_WORD + ')');
const LABEL_RE = /(?:Vertretungsberechtigt(?:e[rn]?)?|Vertreten\s+durch|Geschäftsführer(?:in)?|Geschäftsführung|Geschäftsleitung|(?:Betriebs[\s-]?)?Inhaber(?:in)?|Eigentümer(?:in)?|Gesellschafter(?:in)?|Verantwortlich(?:e[rn]?)?(?:\s+(?:für\s+den\s+Inhalt|nach|i\.\s*S\.\s*d\.|im\s+Sinne\s+(?:des|von)))?)[^:]*:/i;
const TITLE_SKIP_RE = /^(?:(?:Dr|Prof|Dipl|Mag|MBA|M\.?Sc|B\.?Sc|M\.?A|B\.?A|RA|LL\.?M)\.?(?:-[A-Za-zäöüß]+\.?)?\s+)+/;
const ANREDE_SKIP_RE = /^\s*(?:(?:Herr|Frau)\s+)?/;

function normalizeForLabelMatch(plain) {
  if (!plain) return '';
  return String(plain)
    .replace(/\s*\n\s*/g, '\n')
    .replace(/[ \t]+/g, ' ')
    .replace(/\s+:/g, ':')
    .trim();
}

function extractInhaber(rawText) {
  if (!rawText) return '';
  const text = normalizeForLabelMatch(rawText);
  const labelMatch = text.match(LABEL_RE);
  if (!labelMatch) return '';
  let rest = text.slice(labelMatch.index + labelMatch[0].length);
  rest = rest.replace(ANREDE_SKIP_RE, '');
  rest = rest.replace(TITLE_SKIP_RE, '');
  const nameMatch = rest.match(NAME_RE);
  if (!nameMatch) return '';
  const name = nameMatch[1];
  if (name.includes('�')) return '';
  return name;
}

function detectCharsetCorruption(rawHtml) {
  if (!rawHtml) return false;
  const fffdCount = (String(rawHtml).match(/�/g) || []).length;
  return fffdCount > 5;
}

// === Patch 4: URL-Scheme Preservation ===
function urlSchemeOf(url) {
  if (!url) return '';
  try {
    const u = new URL(url);
    return u.protocol.replace(':', '').toLowerCase();
  } catch (e) {
    return '';
  }
}

// === Main ===
const NON_SH = ['niedersachsen', 'mecklenburg-vorpommern', 'mecklenburg vorpommern', 'bremen ', 'brandenburg'];
const out = [];

for (let i = 0; i < dedupItems.length; i++) {
  const lead = (dedupItems[i] && dedupItems[i].json) || {};
  const det = ((detailItems[i] && detailItems[i].json) || {}).result || {};

  const webParsed = readWebsite(i);
  const impParsed = await readImpressum(i);
  const websiteReachable = isReachable(webParsed);
  const impressumReachable = isReachable(impParsed);
  const websiteHtml = websiteReachable ? webParsed.html : '';
  const impressumHtml = impressumReachable ? impParsed.html : '';
  const website_unreachable = !websiteReachable;

  const websiteCorrupt = detectCharsetCorruption(websiteHtml);
  const impressumCorrupt = detectCharsetCorruption(impressumHtml);

  const phone = det.formatted_phone_number || det.international_phone_number || '';
  const websiteUrl = det.website || '';
  // Patch 4: KEIN forced HTTPS mehr — Original-Scheme bleibt erhalten.
  // urlNorm nur trailing-slash-cleaning, Scheme unverändert.
  const websiteUrlNorm = websiteUrl ? websiteUrl.replace(/\/+$/, '') : '';
  const noSsl = urlSchemeOf(websiteUrlNorm || websiteUrl) === 'http';

  const address = det.formatted_address || lead.formatted_address || '';
  const rating = det.rating != null ? det.rating : (lead.rating != null ? lead.rating : null);
  const reviewCount = det.user_ratings_total != null ? det.user_ratings_total : (lead.user_ratings_total || 0);

  const addrLow = address.toLowerCase();
  const outsideSH = NON_SH.some(m => addrLow.includes(m));

  // Email mit Domain-Strict
  const emailScanHtml = stripScriptStyleOnly(websiteHtml) + '\n' + stripScriptStyleOnly(impressumHtml);
  const emails = extractEmails(emailScanHtml);
  const emailResult = pickBestEmail(emails, websiteUrlNorm || websiteUrl);

  // Inhaber-V2
  const impressumPlain = htmlText(impressumHtml);
  const websitePlain = htmlText(websiteHtml);
  const inhaber = extractInhaber(impressumPlain) || extractInhaber(websitePlain);

  const htmlSnippet = website_unreachable ? '' : truncateChars(htmlText(websiteHtml), 3000);

  out.push({
    json: {
      lead_id: lead.lead_id,
      place_id: lead.place_id,
      business_name: det.name || lead.name || '',
      address: address,
      phone: phone,
      website_url: websiteUrlNorm,
      google_rating: rating,
      review_count: reviewCount,
      _hub_name: lead._hub_name,
      _outside_sh: outsideSH,
      _website_unreachable: website_unreachable,
      _website_corrupt: websiteCorrupt,
      _impressum_corrupt: impressumCorrupt,
      _impressum_reachable: impressumReachable,
      _email: emailResult.email,
      _email_domain_mismatch: emailResult.mismatch,
      _inhaber: inhaber,
      _email_candidate_count: emails.size,
      _no_ssl: noSsl,
      _html_snippet: htmlSnippet,
      _places_json: { name: det.name, address, phone, website: websiteUrlNorm, rating, user_ratings_total: reviewCount, business_status: det.business_status || null }
    }
  });
}

return out.filter(it => !it.json._outside_sh);

